penpot.ui.open("ColorSlurp Importer","https://janstieler.github.io/penpot-colorslurp-importer/dist/index.html",{width:400,height:620});const d=/^#([0-9a-fA-F]{3}|[0-9a-fA-F]{4}|[0-9a-fA-F]{6}|[0-9a-fA-F]{8})$/;penpot.ui.onMessage(n=>{if(n.type==="check-colors"){const a=penpot.library.local.colors.map(t=>t.path?`${t.path}/${t.name}`:t.name);penpot.ui.sendMessage({type:"existing-colors",names:a})}if(n.type==="import-colors"){const{paletteName:a,colors:t,numberedPrefix:s}=n;if(typeof a!="string"||!Array.isArray(t))return;const l=new Set(penpot.library.local.colors.map(e=>e.path?`${e.path}/${e.name}`:e.name)),h=String(t.length).length;let p=0,r=0;t.forEach((e,m)=>{if(!d.test(e.hex))return;const c=s?`${String(m+1).padStart(h,"0")}_${e.name}`:e.name,i=`${a}/${c}`;if(l.has(i)){r++;return}const o=penpot.library.local.createColor();o.name=i,o.color=e.hex,o.opacity=Math.min(1,Math.max(0,typeof e.alpha=="number"?e.alpha:1)),p++}),penpot.ui.sendMessage({type:"done",count:p,skipped:r})}});
